// TVMbot Chat Module — search, history, keyboard shortcuts
// Generated by TIER 1 refactor

/**
 * Chat search functionality
 */
const ChatSearch = {
  isOpen: false,
  currentIndex: -1,
  matches: [],

  toggle() {
    const bar = document.getElementById('search-bar');
    const input = document.getElementById('search-input');
    if (!bar) return;
    this.isOpen = !this.isOpen;
    bar.classList.toggle('open', this.isOpen);
    if (this.isOpen) {
      input.focus();
    } else {
      input.value = '';
      document.getElementById('search-count').textContent = '';
      this.clearHighlights();
    }
  },

  search(query) {
    this.clearHighlights();
    this.matches = [];
    this.currentIndex = -1;
    if (!query || query.length < 2) {
      document.getElementById('search-count').textContent = '';
      return;
    }
    const msgs = document.querySelectorAll('.msg');
    msgs.forEach(msg => {
      const bubble = msg.querySelector('.msg-bubble');
      if (bubble && bubble.textContent.toLowerCase().includes(query.toLowerCase())) {
        msg.classList.add('search-highlight');
        this.matches.push(msg);
      }
    });
    document.getElementById('search-count').textContent = this.matches.length + ' found';
    if (this.matches.length > 0) this.goToMatch(0);
  },

  goToMatch(idx) {
    if (this.matches.length === 0) return;
    this.matches.forEach(m => m.classList.remove('search-active'));
    this.currentIndex = idx % this.matches.length;
    const m = this.matches[this.currentIndex];
    m.classList.add('search-active');
    m.scrollIntoView({ behavior: 'smooth', block: 'center' });
  },

  next() {
    if (this.matches.length > 0) this.goToMatch(this.currentIndex + 1);
  },

  clearHighlights() {
    document.querySelectorAll('.msg.search-highlight').forEach(el => {
      el.classList.remove('search-highlight', 'search-active');
    });
    this.matches = [];
  }
};

console.log('[TVMbot] chat.js loaded');
